class FracField(DefaultPrinting):
    """Multivariate distributed rational function field. """

    ring: PolyRing
    gens: tuple[FracElement, ...]
    symbols: tuple[Expr, ...]
    ngens: int
    domain: Domain
    order: MonomialOrder

